func TestNovelStaleBehavior(t *testing.T) {
	s := newTestStore(t)
	now := time.Now().Unix()
	day := int64(86400)

	// Contacted 60 days ago → stale at --days 30.
	seedOpp(t, s, "1", map[string]any{
		"name": "Cold Deal", "status": "Open", "monetary_value": 5000.0,
		"pipeline_id": 1, "assignee_id": 700,
		"date_last_contacted": now - 60*day,
	})
	// Contacted today → fresh, excluded.
	seedOpp(t, s, "2", map[string]any{
		"name": "Warm Deal", "status": "Open", "monetary_value": 1000.0,
		"pipeline_id": 1, "assignee_id": 700,
		"date_last_contacted": now,
	})
	// Never contacted → always stale.
	seedOpp(t, s, "3", map[string]any{
		"name": "Never Touched", "status": "Open", "monetary_value": 2000.0,
		"pipeline_id": 1, "assignee_id": 701,
	})
	// Won (not Open) but very stale → excluded by status filter.
	seedOpp(t, s, "4", map[string]any{
		"name": "Closed", "status": "Won", "monetary_value": 9999.0,
		"date_last_contacted": now - 90*day,
	})

	opps, err := runStale(context.Background(), s.DB(), staleOpts{Days: 30, Status: "Open", Limit: 50}, now)
	if err != nil {
		t.Fatalf("runStale: %v", err)
	}

	ids := map[string]staleOpp{}
	for _, o := range opps {
		ids[o.ID] = o
	}
	if _, ok := ids["1"]; !ok {
		t.Errorf("opp 1 (60d stale) should appear; got ids %v", keysOf(ids))
	}
	if _, ok := ids["2"]; ok {
		t.Errorf("opp 2 (contacted today) should be excluded")
	}
	if _, ok := ids["3"]; !ok {
		t.Errorf("opp 3 (never contacted) should appear")
	}
	if _, ok := ids["4"]; ok {
		t.Errorf("opp 4 (Won status) should be excluded")
	}
	// Never-contacted (days_stale = -1) sorts first.
	if len(opps) == 0 || opps[0].ID != "3" {
		t.Errorf("never-contacted opp should sort first; got order %v", orderOf(opps))
	}
	if o := ids["1"]; o.DaysStale < 59 || o.DaysStale > 61 {
		t.Errorf("opp 1 days_stale = %d, want ~60", o.DaysStale)
	}

	// Group-by-assignee aggregation: 700 has 1 cold (opp1), 701 has 1 cold (opp3).
	groups, err := runStaleByAssignee(context.Background(), s.DB(), staleOpts{Days: 30, Status: "Open"}, now)
	if err != nil {
		t.Fatalf("runStaleByAssignee: %v", err)
	}
	byOwner := map[string]staleByAssignee{}
	for _, g := range groups {
		byOwner[g.AssigneeID] = g
	}
	if g, ok := byOwner["700"]; !ok || g.ColdCount != 1 || g.ColdValue != 5000 {
		t.Errorf("owner 700 = %+v, want count 1 value 5000", g)
	}
	if g, ok := byOwner["701"]; !ok || g.ColdCount != 1 || g.ColdValue != 2000 {
		t.Errorf("owner 701 = %+v, want count 1 value 2000", g)
	}
}

func keysOf(m map[string]staleOpp) []string {
	out := make([]string, 0, len(m))
	for k := range m {
		out = append(out, k)
	}
	return out
}

func orderOf(opps []staleOpp) []string {
	out := make([]string, 0, len(opps))
	for _, o := range opps {
		out = append(out, o.ID)
	}
	return out
}
